#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <stdint.h>
#include <stdbool.h>
typedef struct {
    int y, s, e;
} line;

int compare(const void *a, const void *b) {
    line *l1 = (line *)a;
    line *l2 = (line *)b;
    if (l1->y < l2->y) return -1;
    if (l1->y > l2->y) return 1;
    if (l1->e - l1->s < l2->e - l2->s) return -1;
    if (l1->e - l1->s > l2->e - l2->s) return 1;
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, P;
        scanf("%d %d", &N, &P);
        line lines[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d %d", &lines[i].y, &lines[i].s, &lines[i].e);
        }
        qsort(lines, N, sizeof(line), compare);
        int count = 0;
        for (int i = 0; i < N; i++) {
            int time = lines[i].e - lines[i].s + (lines[i].y > 0 ? lines[i].y : 0);
            if (P >= time) {
                P -= time;
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

