// COMPLETE, COMPILABLE Java code
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static class line implements Comparable<line> {
        int y, s, e;
        public line(int y, int s, int e) {
            this.y = y;
            this.s = s;
            this.e = e;
        }
        @Override
        public int compareTo(line o) {
            if (y < o.y) return -1;
            if (y > o.y) return 1;
            return Integer.compare(e - s, o.e - o.s);
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int P = sc.nextInt();
            line[] lines = new line[N];
            for (int i = 0; i < N; i++) {
                lines[i] = new line(sc.nextInt(), sc.nextInt(), sc.nextInt());
            }
            Arrays.sort(lines);
            int count = 0;
            for (int i = 0; i < N; i++) {
                int time = lines[i].e - lines[i].s + (lines[i].y > 0 ? lines[i].y : 0);
                if (P >= time) {
                    P -= time;
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

