const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, P] = readline().split(' ').map(Number);
    const lines = [];
    for (let j = 0; j < N; j++) {
        const [y, s, e] = readline().split(' ').map(Number);
        lines.push([y, s, e]);
    }
    lines.sort((a, b) => a[0] - b[0] || (a[2] - a[1]) - (b[2] - b[1]));
    let count = 0;
    for (let j = 0; j < N; j++) {
        const time = lines[j][2] - lines[j][1] + (lines[j][0] > 0 ? lines[j][0] : 0);
        if (P >= time) {
            P -= time;
            count++;
        }
    }
    console.log(count);
}

